from flask import Flask, request, jsonify
from selenium import webdriver
from selenium.webdriver.chrome.service import Service
from selenium.webdriver.chrome.options import Options
from webdriver_manager.chrome import ChromeDriverManager
import boto3
import os
import time

app = Flask(__name__)

# Configure AWS S3
s3_client = boto3.client('s3')
BUCKET_NAME = 'your-s3-bucket-name'

# Configure Chrome options for headless browsing
chrome_options = Options()
chrome_options.add_argument("--headless")
chrome_options.add_argument("--no-sandbox")
chrome_options.add_argument("--disable-dev-shm-usage")

@app.route('/screenshot', methods=['POST'])
def screenshot():
    data = request.json
    url = data.get('url')
    
    if not url:
        return jsonify({'error': 'URL is required'}), 400

    # Set up headless Chrome
    service = Service(ChromeDriverManager().install())
    driver = webdriver.Chrome(service=service, options=chrome_options)

    try:
        driver.get(url)
        time.sleep(2)  # Wait for the page to load
        screenshot_path = f"/tmp/screenshot_{int(time.time())}.png"
        driver.save_screenshot(screenshot_path)

        # Upload to S3
        s3_client.upload_file(screenshot_path, BUCKET_NAME, os.path.basename(screenshot_path))
        os.remove(screenshot_path)

        return jsonify({'message': 'Screenshot taken', 'url': f'https://{BUCKET_NAME}.s3.amazonaws.com/{os.path.basename(screenshot_path)}'}), 200

    except Exception as e:
        return jsonify({'error': str(e)}), 500

    finally:
        driver.quit()

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)